import os
import subprocess

def backup(directory, format):
    # Validate the input directory and format
    if not os.path.isdir(directory):
        raise ValueError("Invalid directory")
    if format not in ["tar.gz", "tar.bz2", "zip", "7z"]:
        raise ValueError("Unsupported format")

    # Create the archive file name
    archive_name = f"{directory}.{format}"

    # Use subprocess to run the compression command
    if format == "tar.gz":
        subprocess.run(["tar", "-czf", archive_name, directory], check=True, shell=False)
    elif format == "tar.bz2":
        subprocess.run(["tar", "-cjf", archive_name, directory], check=True, shell=False)
    elif format == "zip":
        subprocess.run(["zip", "-r", archive_name, directory], check=True, shell=False)
    else:  # format == "7z"
        subprocess.run(["7z", "a", "-tzip", archive_name, directory], check=True, shell=False)